                    AscendC::Sub(yLocal, xLocal, mean, curTileLen);
                    AscendC::Mul(yLocal, yLocal, invStd, curTileLen);

                    AscendC::DataCopy(yGm_[gmOffset], yLocal, curTileLen);

                    outQueueY_.FreeTensor(yLocal);
                    inQueueX_.FreeTensor(xLocal);
                }
            }
        }
    }

